using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; using NuamExchange.Domain.Classifications;
namespace NuamExchange.Infrastructure.Persistence;
public sealed class ClassificationConfiguration:IEntityTypeConfiguration<Classification>{public void Configure(EntityTypeBuilder<Classification> b){b.ToTable("Classifications");b.HasKey(x=>x.Id);b.Property(x=>x.Id).HasMaxLength(40).ValueGeneratedNever();b.Property(x=>x.Market).HasMaxLength(50).IsRequired();b.Property(x=>x.Source).HasMaxLength(50).IsRequired();b.Property(x=>x.Instrument).HasMaxLength(30).IsRequired();b.Property(x=>x.PaymentDate).HasColumnType("date").IsRequired();b.Property(x=>x.Description).HasMaxLength(500).IsRequired();b.Property(x=>x.EventSequence).HasMaxLength(30).IsRequired();b.Property(x=>x.UpdateFactor).HasColumnType("decimal(18,6)").IsRequired();b.Property(x=>x.Amount).HasColumnType("decimal(18,2)").IsRequired();b.Property(x=>x.Status).HasConversion<string>().HasMaxLength(20).IsRequired();b.Property(x=>x.CreatedAt).HasColumnType("datetimeoffset").IsRequired();b.Property(x=>x.UpdatedAt).HasColumnType("datetimeoffset").IsRequired();b.Property(x=>x.RowVersion).IsRowVersion().IsConcurrencyToken();b.HasIndex(x=>new{x.FiscalYear,x.Market,x.Instrument,x.PaymentDate,x.EventSequence}).IsUnique();b.HasIndex(x=>x.FiscalYear);b.HasIndex(x=>x.Market);b.HasIndex(x=>x.Status);b.HasIndex(x=>x.PaymentDate);b.HasData(ClassificationSeed.Items);}}
